mapper.select:
SELECT ID, MEMBER_EMAIL, MEMBER_PASSWORD, MEMBER_PICTURE, MEMBER_NAME, MEMBER_NICKNAME, MEMBER_PROVIDER
FROM TBL_OAUTH_MEMBER
WHERE MEMBER_EMAIL = #{memberEmail}
  AND MEMBER_PASSWORD = #{memberPassword}

SELECT ID, MEMBER_EMAIL, MEMBER_PASSWORD, MEMBER_PICTURE, MEMBER_NAME, MEMBER_NICKNAME, MEMBER_PROVIDER
FROM TBL_OAUTH_MEMBER
WHERE ID = #{id}

mapper.update:
UPDATE TBL_OAUTH_MEMBER
SET MEMBER_PASSWORD = #{memberPassword}, MEMBER_PICTURE = #{memberPicture}, MEMBER_NAME = #{memberName}, MEMBER_NICKNAME = #{memberNickname}, MEMBER_PROVIDER = #{memberProvider}
WHERE ID = #{id};
